long long nCr(int n, int r) {
    if (r < 0 || r > n) return 0;
    if (r == 0 || r == n) return 1;
    if (r > n - r) r = n - r;

    long long result = 1;
    for (int i = 1; i <= r; i++) {
        result = result * (n - r + i) / i;
    }
    return result;
}

// CALCULATING nCr IN SHORT TIME BUT MAY LEAD TO OVERFLOW FOR VERY LARGE NUMBERS

/*  AUTHOR:AKASH JAIN
*       
*   DATE:18/10/2020 
*/

ll ncr(ll n,ll r)
{
    if(r>n-r)
        r=n-r;      //nCr = nC(n-r)
    ll ans=1;
    FOR(i,1,r)
    {
        ans*=n-r+i;
        ans/=i;
    }
    return ans;
}

/*This code will start multiplication of the numerator from the smaller end, 
and as the product of any k consecutive integers is divisible by k!, 
there will be no divisibility problem. But the possibility of overflow is still there, 
another useful trick may be dividing n - r + i and i by their GCD before doing the multiplication 
and division (and still overflow may occur).*/

// CALCULATING nCr BY PASCALS TRIANGLES
/*  AUTHOR:AKASH JAIN
*   USERNAME:akash19jain    
*   DATE:09/09/2019 
*/
#define MAX 1000    //assuming we need first 1000 rows 

ll triangle[MAX+1][MAX+1];
void makeTriangle()
{
    triangle[0][0]=1;   //C(0,0)=1;

    FOR(i,1,MAX-1)
    {
        triangle[i][0]=1;   //C(i,0)=1;
        FOR(j,1,i)
            triangle[i][j]=triangle[i-1][j-1]+triangle[i-1][j];
    }

}
ll ncr(ll n,ll r)
{
    return triangle[n][r];
}

/*In this approach, you'll be actually building up the Pascal's Triangle. 
The dynamic approach is much faster than the recursive one (the first one is O(n^2) while the other is exponential).
 However, you'll need to use O(n^2) memory too. 
 Then you can look up any C(n, r) in O(1) time. */

// CALCULATING nC0 + nC1 + ... + nCr

/*  AUTHOR:AKASH JAIN
*   USERNAME:akash19jain    
*   DATE:09/09/2019 
*/

#define MAX1 100005    //assuming we need first 1000 rows 

ll triangle[MAX1+1];
ll makeTriangle(ll n,ll r)
{
	MEM(triangle,0);
    triangle[0]=1;   //C(0,0)=1;

    FOR(i,1,n)
    {
        FORD(j,i,1)
		{
            triangle[j]+=triangle[j-1];
			triangle[j]%=MOD;
		}
    }
	ll ans=0;
	REP(i,r+1)
	{
		ans+=triangle[i];
		ans%=MOD;
	}
	return ans;
}

public class Combination {
    public static int nCr(int n, int r) {
        if (r < 0 || r > n) {
            return 0;
        }
        if (r == 0 || r == n) {
            return 1;
        }
        int k = Math.min(r, n - r);
        long result = 1;
        for (int i = 1; i <= k; i++) {
            result = result * (n - k + i) / i;
        }
        return (int) result;
    }
}

fun nCr(n: Int, r: Int): Long {
    if (r < 0 || r > n) {
        return 0
    }
    val k = minOf(r, n - r)
    var result = 1L
    for (i in 1..k) {
        result = result * (n - k + i) / i
    }
    return result
}

func nCr(_ n: Int, _ r: Int) -> Int {
    if r < 0 || r > n { return 0 }
    if r == 0 || r == n { return 1 }

    let k = min(r, n - r)
    var result = 1
    if k == 0 { return 1 }

    for i in 1...k {
        result = result * (n - k + i) / i
    }

    return result
}
